package com.enterprise.auth.mfa;

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import java.security.SecureRandom;
import java.util.*;

@Service
public class MfaBackupCodeService {
    
    @Autowired
    private BackupCodeRepository backupCodeRepository;
    
    @Autowired
    private PasswordEncoder passwordEncoder;
    
    private static final int CODE_LENGTH = 8;
    private static final int CODE_COUNT = 10;
    private static final SecureRandom random = new SecureRandom();
    
    public List<String> generateBackupCodes(String userId) {
        List<String> codes = new ArrayList<>();
        Set<String> uniqueCodes = new HashSet<>();
        
        while (uniqueCodes.size() < CODE_COUNT) {
            StringBuilder code = new StringBuilder();
            for (int i = 0; i < CODE_LENGTH; i++) {
                code.append(random.nextInt(10));
            }
            uniqueCodes.add(code.toString());
        }
        
        codes.addAll(uniqueCodes);
        
        // Store encrypted codes in database
        List<BackupCodeEntity> entities = codes.stream()
            .map(code -> {
                BackupCodeEntity entity = new BackupCodeEntity();
                entity.setUserId(userId);
                entity.setEncryptedCode(passwordEncoder.encode(code));
                entity.setUsed(false);
                entity.setCreatedAt(new Date());
                return entity;
            })
            .collect(ArrayList::new, ArrayList::add, ArrayList::addAll);
        
        backupCodeRepository.saveAll(entities);
        return codes;
    }
    
    public boolean validateBackupCode(String userId, String code) {
        BackupCodeEntity entity = backupCodeRepository.findByUserIdAndEncryptedCode(
            userId, passwordEncoder.encode(code));
        
        if (entity != null && !entity.isUsed()) {
            entity.setUsed(true);
            entity.setUsedAt(new Date());
            backupCodeRepository.save(entity);
            return true;
        }
        return false;
    }
    
    public void invalidateBackupCodes(String userId) {
        backupCodeRepository.deleteByUserId(userId);
    }
    
    public boolean hasValidBackupCodes(String userId) {
        return backupCodeRepository.existsByUserIdAndUsedFalse(userId);
    }
}

